#include <bits/stdc++.h>
using namespace std;
int n,q,k;
vector<int> prime;
bitset<100000005> vis;
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n>>q;
    for(int i=2;i<=n;i+=(i==2)?1:2)
    {
        if(vis[i])  continue;
        for(int j=i;j<=n;j+=i)
        {
            vis[j]=1;
        }
        prime.push_back(i);
    }
    while(q--)
    {
        int x;
        cin>>x;
        cout<<prime[x-1]<<'\n';
    }
    return 0;
}
